import { Switch, Route } from "wouter";
import { queryClient } from "./lib/queryClient";
import { QueryClientProvider } from "@tanstack/react-query";
import { Toaster } from "@/components/ui/toaster";
import { TooltipProvider } from "@/components/ui/tooltip";
import { AuthProvider } from "@/contexts/AuthContext";
import ProtectedRoute from "@/components/ProtectedRoute";
import Navigation from "@/components/Navigation";
import Home from "@/pages/Home";
import Pricing from "@/pages/Pricing";
import Contact from "@/pages/Contact";
import Onboarding from "@/pages/Onboarding";
import SetupSuccess from "@/pages/SetupSuccess";
import Dashboard from "@/pages/Dashboard";
import AgentLogin from "@/pages/AgentLogin";
import AgentDashboard from "@/pages/AgentDashboard";
import TaskDetail from "@/pages/TaskDetail";
import NotFound from "@/pages/not-found";
import RequestPro from "@/pages/RequestPro";
import AdminDashboard from "@/pages/AdminDashboard";
import MagnetDashboard from "@/pages/MagnetDashboard";
import SetupFormsDashboard from "@/pages/SetupFormsDashboard";
import Login from "@/pages/Login";

function Router() {
  return (
    <div className="min-h-screen bg-background text-foreground">
      <Navigation />
      <Switch>
        <Route path="/" component={Home} />
        <Route path="/pricing" component={Pricing} />
        <Route path="/contact" component={Contact} />
        <Route path="/login" component={Login} />
        <Route path="/setup/success" component={SetupSuccess} />
        <Route path="/setup/new">
          <ProtectedRoute>
            <Onboarding adminMode={true} />
          </ProtectedRoute>
        </Route>
        <Route path="/setup/:token" component={Onboarding} />
        <Route path="/task/:token/:taskId" component={TaskDetail} />
        <Route path="/request-pro" component={RequestPro} />
        <Route path="/admin">
          <ProtectedRoute>
            <Dashboard />
          </ProtectedRoute>
        </Route>
        <Route path="/admin/requests">
          <ProtectedRoute>
            <AdminDashboard />
          </ProtectedRoute>
        </Route>
        <Route path="/admin/magnets">
          <ProtectedRoute>
            <MagnetDashboard />
          </ProtectedRoute>
        </Route>
        <Route path="/admin/setup-forms">
          <ProtectedRoute>
            <SetupFormsDashboard />
          </ProtectedRoute>
        </Route>
        <Route path="/agent" component={AgentLogin} />
        <Route path="/agent/dashboard">
          <ProtectedRoute>
            <AgentDashboard />
          </ProtectedRoute>
        </Route>
        {/* Fallback to 404 */}
        <Route component={NotFound} />
      </Switch>
    </div>
  );
}

function App() {
  return (
    <QueryClientProvider client={queryClient}>
      <TooltipProvider>
        <AuthProvider>
          <Toaster />
          <Router />
        </AuthProvider>
      </TooltipProvider>
    </QueryClientProvider>
  );
}

export default App;

