export async function registerRoutes(app: Express): Promise<Server> {
  // Add morgan logging for all requests
  app.use(morgan('combined', {
    stream: {
      write: (message: string) => console.log(message.trim())
    }
  }));
  // Setup Routes - Public

  // GET /api/setup/:token/customer-data - Get customer data for pre-population
  app.get("/api/setup/:token/customer-data", publicApiLimiter, async (req, res) => {
    await createAuditLog(req, '/api/setup/:token/customer-data');

    try {
      const { token } = req.params;

      console.log(`📋 Looking up customer data for token: ${token}`);

      // Look up order item by activation code
      const orderItem = await storage.getOrderItemByActivationCode(token);

      if (!orderItem) {
        console.log(`⚠️  Token not found: ${token}`);
        // Token not found - return empty data (user will fill manually)
        return res.json({
          found: false,
          prefilled: false,
          data: {},
          message: 'Token not found. Please fill in your information manually.'
        });
      }

      const { item, order } = orderItem;

      // Check if QR code already used (one-time use enforcement)
      if (item.activationStatus === 'activated') {
        console.log(`❌ Token already activated: ${token}`);
        return res.status(409).json({
          found: true,
          prefilled: false,
          alreadyActivated: true,
          activatedAt: item.activatedAt,
          activatedByEmail: item.activatedByEmail,
          message: 'This QR code has already been activated and cannot be used again.',
          data: {}
        });
      }

      // Return customer data for pre-fill
      console.log(`✅ Found customer data for: ${order.customerEmail}`);

      res.json({
        found: true,
        prefilled: true,
        alreadyActivated: false,
        data: {
          fullName: order.customerName,
          email: order.customerEmail,
          phone: order.customerPhone,
          streetAddress: order.shipAddressLine1,
          addressLine2: order.shipAddressLine2 || '',
          city: order.shipCity,
          state: order.shipState,
          postalCode: order.shipZip,
          country: order.shipCountry || 'US',
        },
        itemId: item.id,
        orderId: order.id,
        activationCode: token
      });

    } catch (error: any) {
      console.error('Error fetching customer data:', error);
      return handleError(error, 'setup/customer-data lookup', res);
    }
  });

  // POST /api/setup/activate - Activate household setup (with admin mode support)
  app.post("/api/setup/activate", publicApiLimiter, async (req, res) => {
    await createAuditLog(req, '/api/setup/activate');
    try {
      const validatedData = setupActivateSchema.parse(req.body);
      const { 
        token, 
        skipWelcomeEmail = false,
        // Personal details
        fullName,
        phone,
        email,
        preferredContact,
        preferredContactTime,
        smsOptIn,
        // Home details
        country,
        streetAddress,
        city,
        state,
        postalCode,
        zip, // Legacy support
        homeType, 
        sqft, 
        hvacType, 
        heatPump,
        waterHeater, 
        roofAgeYears,
        isOwner,
        // Interest details
        interestType,
        needConsultation,
        budgetRange,
        timelineToProceed,
        notes
      } = validatedData;

      // ==== SECURITY: Derive Admin Mode from Authentication (NEVER trust client) ====
      const { getUserFromAuth } = await import('./middleware/auth');
      const authUser = await getUserFromAuth(req);

      // Check if this is an authenticated admin (server-derived, never from client)
      const isAuthenticatedAdmin = authUser && authUser.role === 'admin';
      const allowAdminCreation = process.env.ALLOW_ADMIN_SETUP_CREATION === 'true';

      // Admin mode is ONLY enabled if:
      // 1. User is authenticated as admin
      // 2. Feature flag allows it
      // 3. No token provided (admin creates without QR)
      const isAdminMode = isAuthenticatedAdmin && allowAdminCreation && !token;

      const createdBy = isAdminMode ? 'admin' : 'customer';
      const createdByUserId = isAdminMode ? authUser.id : null;

      if (isAdminMode) {
        console.log(`🔒 Admin-created household by ${authUser.email} (server-verified)`);
      }

      // Use postalCode or fall back to zip for legacy support
      const zipCode = postalCode || zip;

      // ==== Token Validation (Skip for admin-created households) ====
      let magnet = null;
      let claimedItem = null;

      if (!isAdminMode) {
        if (!token) {
          return res.status(400).json({ error: "Token required for customer activation" });
        }

        // Try atomic claim for new order system (prevents race conditions)
        claimedItem = await storage.claimOrderMagnetItemForActivation(
          token,
          email || fullName || 'Unknown',
          new Date()
        );

        // Validate token exists in legacy magnet system (or was just claimed from order system)
        magnet = await storage.getMagnetByToken(token);

        if (!magnet && !claimedItem) {
          // Token not found in either system - check if it was already activated
          const existingItem = await storage.getOrderItemByActivationCode(token);
          if (existingItem && existingItem.item.activationStatus === 'activated') {
            console.log(`❌ Duplicate activation attempt blocked for token: ${token}`);
            return res.status(409).json({ 
              error: "This QR code has already been activated and cannot be used again.",
              alreadyActivated: true,
              activatedAt: existingItem.item.activatedAt,
              activatedByEmail: existingItem.item.activatedByEmail
            });
          }

          // Token doesn't exist at all
          return res.status(404).json({ error: "Invalid or expired token" });
        }
      }

      // ==== Household Creation/Update ====
      let household = null;

      // For admin-created households, skip token lookup
      if (!isAdminMode && token) {
        household = await storage.getHouseholdByToken(token);
      }

      if (household) {
        // Update existing household
        household = await storage.updateHousehold(household.id, {
          name: fullName || household.name,
          email: email || household.email,
          phone: phone || household.phone,
          address: streetAddress || household.address,
          city: city || household.city,
          state: state || household.state,
          zip: zipCode || household.zip,
          homeType: home_type as 'single_family' | 'condo' | 'townhouse' | 'apartment' | 'mobile' | 'other',
          country: country || 'US',
          preferredContact,
          preferredContactTime,
          smsOptIn: smsOptIn ?? false,
          sqft,
          hvacType: hvac_type,
          heatPump,
          waterHeater: water_heater,
          roofAgeYears: roof_age_years,
          interestType,
          needConsultation,
          budgetRange,
          timelineToProceed,
          notes,
          activatedAt: new Date(),
        });

        // Audit event for household update
        await storage.createAuditEvent({
          eventType: 'household_updated',
          actorType: isAdminMode ? 'admin' : 'customer',
          actorId: createdByUserId || 'customer',
          actorEmail: authUser?.email || email || '',
          householdId: household.id,
          metadata: JSON.stringify({
            updatedFields: Object.keys(validatedData).filter(k => k !== 'token'),
            adminMode: isAdminMode
          }),
        });
      } else {
        // Create new household
        const { SYSTEM_AGENT_ID } = await import('./storage');

        // Generate unique token placeholder for admin-created households
        // This prevents QR inventory collisions and maintains referential integrity
        let householdToken: string;

        if (isAdminMode) {
          // Generate collision-resistant token for admin-created households
          // Loop until we find an unused token (extremely unlikely to iterate)
          let attempts = 0;
          const MAX_ATTEMPTS = 10;

          do {
            householdToken = `admin-${uuidv4()}`;
            const existing = await storage.getHouseholdByToken(householdToken);

            if (!existing) {
              break; // Token is unique
            }

            attempts++;
            if (attempts >= MAX_ATTEMPTS) {
              console.error('Failed to generate unique admin token after', MAX_ATTEMPTS, 'attempts');
              return res.status(500).json({ error: "Failed to generate unique household identifier" });
            }
          } while (true);

          console.log(`✅ Generated unique admin token: ${householdToken}`);
        } else {
          householdToken = token;
        }

        household = await storage.createHousehold({
          id: uuidv4(),
          magnetToken: householdToken,
          agentId: magnet?.agentId ?? SYSTEM_AGENT_ID,
          name: fullName || email?.split('@')[0] || 'User',
          email: email || '',
          phone: phone || '',
          address: streetAddress || '',
          city: city || '',
          state: state || '',
          zip: zipCode || '',
          homeType: homeType as 'single_family' | 'condo' | 'townhouse' | 'apartment' | 'mobile' | 'other',
          country: country || 'US',
          preferredContact,
          preferredContactTime,
          sqft,
          hvacType: hvacType,
          heatPump,
          waterHeater: waterHeater,
          roofAgeYears: roofAgeYears,
          interestType,
          needConsultation,
          budgetRange,
          timelineToProceed,
          notes,
          smsOptIn: smsOptIn ?? false,
          activatedAt: new Date(),
          createdBy,
          createdByUserId,
        });

        // Audit event for household creation
        const eventType = isAdminMode ? 'admin_household_created' : 'qr_activated';
        await storage.createAuditEvent({
          eventType,
          actorType: isAdminMode ? 'admin' : 'customer',
          actorId: createdByUserId || 'customer',
          actorEmail: authUser?.email || email || '',
          householdId: household.id,
          metadata: JSON.stringify({
            adminMode: isAdminMode,
            skipWelcomeEmail,
            source: isAdminMode ? 'admin_dashboard' : 'qr_activation',
            magnetToken: householdToken,
            qrInventoryAffected: !isAdminMode, // Admin-created households don't affect QR inventory
            placeholderToken: isAdminMode, // Indicates this is an admin-generated placeholder
            welcomeEmailScheduled: !skipWelcomeEmail && !!household.email
          }),
        });
      }

      if (!household) {
        return res.status(500).json({ error: "Failed to create/update household" });
      }

      // Get climate zone and generate schedule
      const climateZone = getClimateZone(zipCode || '');
      const coreTasks = generateCoreSchedule(climateZone);

      // Build initial schedule with proper due dates
      const climateHousehold: ClimateHousehold = {
        id: household.id,
        zip: household.zip,
        homeType: household.homeType,
        climateZone,
      };
      const scheduledTasks = buildInitialSchedule(climateHousehold, coreTasks);

      // Create schedules for core tasks with calculated due dates
      const schedules = [];
      for (const scheduled of scheduledTasks) {
        const schedule = await storage.createSchedule({
          householdId: household.id,
          taskName: scheduled.task.name,
          description: scheduled.task.description,
          frequencyMonths: scheduled.task.frequencyMonths,
          climateZone,
          priority: scheduled.task.priority,
        });
        schedules.push(schedule);

        // Queue email reminder 7 days before due date
        const reminderDate = new Date(scheduled.next_due_date);
        reminderDate.setDate(reminderDate.getDate() - 7);

        await storage.createReminderQueue({
          householdId: household.id,
          scheduleId: schedule.id,
          taskName: scheduled.task.name,
          taskDescription: scheduled.task.description,
          dueDate: scheduled.next_due_date,
          runAt: reminderDate,
          reminderType: 'email',
          message: `Reminder: ${scheduled.task.name} is due in 7 days`,
        });
      }

      // Send welcome email (skip for admin-created unless explicitly requested)
      const shouldSendWelcomeEmail = household.email && (!isAdminMode || !skipWelcomeEmail);
      let welcomeEmailSent = false;
      let welcomeEmailError = null;

      if (shouldSendWelcomeEmail) {
        try {
          const dashboardUrl = process.env.PUBLIC_BASE_URL 
            ? `${process.env.PUBLIC_BASE_URL}/admin`
            : "http://localhost:5000/admin";

          await sendWelcomeEmail({
            email: household.email,
            homeType: household.homeType,
            climateZone,
            taskCount: schedules.length,
            dashboardUrl,
          });
          welcomeEmailSent = true;
          console.log(`✅ Welcome email sent to ${household.email}`);
        } catch (emailError) {
          console.error("Failed to send welcome email:", emailError);
          welcomeEmailError = emailError instanceof Error ? emailError.message : 'Unknown error';
          // Don't fail the activation if email fails
        }
      }

      // Audit event for welcome email outcome (compliance requirement)
      if (isAdminMode) {
        await storage.createAuditEvent({
          eventType: 'household_updated',
          actorType: 'system',
          actorId: 'system',
          actorEmail: authUser?.email || 'system',
          householdId: household.id,
          metadata: JSON.stringify({
            action: 'welcome_email_processing',
            skipWelcomeEmailRequested: skipWelcomeEmail,
            shouldSendWelcomeEmail,
            welcomeEmailSent,
            welcomeEmailError,
            recipientEmail: household.email || 'none',
            adminMode: true
          }),
        });
      }

      // Note: QR code status already updated by atomic claim (claimOrderMagnetItemForActivation)
      // No need to update again here (only for customer activations)

      // Record activation event
      await storage.createEvent({
        householdId: household.id,
        eventType: 'activated',
        eventData: JSON.stringify({ 
          zip, 
          homeType, 
          climate_zone: climateZone,
          tasks_created: schedules.length,
          welcome_email_sent: shouldSendWelcomeEmail,
          admin_created: isAdminMode
        }),
      });

      res.json({
        success: true,
        household: {
          id: household.id,
          token: household.magnetToken,
          zip: household.zip,
          homeType: household.homeType,
          climateZone,
        },
        schedules: schedules.map(s => ({
          taskName: s.taskName,
          description: s.description,
          frequencyMonths: s.frequencyMonths,
          priority: s.priority,
        })),
        firstTaskDue: scheduledTasks.length > 0 
          ? scheduledTasks.sort((a, b) => a.next_due_date.getTime() - b.next_due_date.getTime())[0].next_due_date.toISOString()
          : new Date().toISOString(),
      });
    } catch (error: any) {
      return handleError(error, 'setup/activate', res);
    }
  });

  // POST /api/setup/preview - Preview tasks without persistence
  app.post("/api/setup/preview", publicApiLimiter, async (req, res) => {
    await createAuditLog(req, '/api/setup/preview');
    try {
      const validatedData = setupPreviewSchema.parse(req.body);
      const { zip, homeType } = validatedData;

      // Get climate zone and generate schedule
      const climateZone = getClimateZone(zip);
      const coreTasks = generateCoreSchedule(climateZone);

      // Build initial schedule with proper due dates (no persistence)
      const previewHousehold: ClimateHousehold = {
        id: 'preview',
        zip,
        homeType: homeType,
        climateZone,
      };
      const scheduledTasks = buildInitialSchedule(previewHousehold, coreTasks);

      // Return the first 6 tasks with dates
      const taskPreviews = scheduledTasks
        .slice(0, 6)
        .sort((a, b) => a.task.priority - b.task.priority)
        .map(scheduled => ({
          taskName: scheduled.task.name,
          description: scheduled.task.description,
          frequencyMonths: scheduled.task.frequencyMonths,
          priority: scheduled.task.priority,
          nextDueDate: scheduled.next_due_date.toISOString(),
          taskCode: scheduled.task_code,
        }));

      res.json({
        success: true,
        climateZone,
        tasks: taskPreviews,
        totalTasks: coreTasks.length,
      });
    } catch (error: any) {
      return handleError(error, 'setup/preview', res);
    }
  });

  // POST /api/tasks/complete - Mark task as completed and schedule next occurrence
  app.post("/api/tasks/complete", async (req, res) => {
    try {
      const validatedData = taskCompleteSchema.parse(req.body);
      const { householdToken, task_code } = validatedData;

      // Get household by token
      const household = await storage.getHouseholdByToken(householdToken);
      if (!household) {
        return res.status(404).json({ error: "Household not found" });
      }

      // Find the schedule for this task
      const schedule = await storage.getScheduleByHouseholdAndTask(household.id, task_code);
      if (!schedule) {
        return res.status(404).json({ error: "Task not found" });
      }

      // Calculate next due date based on frequency
      const now = new Date();
      const nextDueDate = new Date(now);
      nextDueDate.setMonth(nextDueDate.getMonth() + schedule.frequencyMonths);

      // Record task completion
      await storage.createTaskCompletion({
        householdId: household.id,
        scheduleId: schedule.id,
        taskCode: task_code,
        completedAt: now,
        nextDueDate,
      });

      // Queue next reminder (7 days before next due date)
      const nextReminderDate = new Date(nextDueDate);
      nextReminderDate.setDate(nextReminderDate.getDate() - 7);

      await storage.createReminderQueue({
        householdId: household.id,
        scheduleId: schedule.id,
        taskName: schedule.taskName,
        taskDescription: schedule.description || undefined,
        dueDate: nextDueDate,
        runAt: nextReminderDate,
        reminderType: 'email',
        message: `Reminder: ${schedule.taskName} is due in 7 days`,
      });

      // Create completion event
      await storage.createEvent({
        householdId: household.id,
        eventType: 'task_completed',
        eventData: JSON.stringify({
          taskCode: task_code,
          taskName: schedule.taskName,
          completedAt: now.toISOString(),
          nextDueDate: nextDueDate.toISOString(),
        }),
      });

      res.json({
        success: true,
        message: `Task "${schedule.taskName}" marked as completed`,
        nextDueDate: nextDueDate.toISOString(),
        reminderScheduled: nextReminderDate.toISOString(),
      });
    } catch (error: any) {
      console.error("Error completing task:", error);
      if (error?.name === 'ZodError') {
        res.status(400).json({ error: "Invalid input data", details: error.errors });
      } else {
        res.status(500).json({ error: "Failed to complete task" });
