              <div className="space-y-2">
                <Label htmlFor="create-zip">ZIP Code *</Label>
                <Input
                  id="create-zip"
                  data-testid="input-create-zip"
                  placeholder="12345"
                  value={createForm.zip}
                  onChange={(e) =>
                    setCreateForm((prev) => ({ ...prev, zip: e.target.value }))
                  }
                  required
                />
              </div>

              <div className="space-y-2 col-span-2">
                <Label htmlFor="create-homeType">Home Type *</Label>
                <Select
                  value={createForm.homeType}
                  onValueChange={(value: typeof createForm.homeType) =>
                    setCreateForm((prev) => ({ ...prev, homeType: value }))
                  }
                >
                  <SelectTrigger id="create-homeType" data-testid="select-create-hometype">
                    <SelectValue />
                  </SelectTrigger>
                  <SelectContent>
                    <SelectItem value="single_family">Single Family Home</SelectItem>
                    <SelectItem value="condo">Condo</SelectItem>
                    <SelectItem value="townhouse">Townhouse</SelectItem>
                    <SelectItem value="apartment">Apartment</SelectItem>
                  </SelectContent>
                </Select>
              </div>
            </div>

            <div className="flex items-center space-x-2 pt-2">
              <Checkbox
                id="skipWelcomeEmail"
                data-testid="checkbox-skip-welcome"
                checked={createForm.skipWelcomeEmail}
                onCheckedChange={(checked) =>
                  setCreateForm((prev) => ({ ...prev, skipWelcomeEmail: !!checked }))
                }
              />
              <Label
                htmlFor="skipWelcomeEmail"
                className="text-sm font-normal cursor-pointer"
              >
                Skip welcome email
              </Label>
            </div>
          </div>

          <DialogFooter>
            <Button
              variant="outline"
              onClick={() => setShowCreateDialog(false)}
              data-testid="button-cancel-create"
              disabled={createHouseholdMutation.isPending}
            >
              Cancel
            </Button>
            <Button
              onClick={() => createHouseholdMutation.mutate(createForm)}
              data-testid="button-submit-create"
              disabled={
                !createForm.fullName ||
                !createForm.email ||
                !createForm.zip ||
                createHouseholdMutation.isPending
              }
            >
              {createHouseholdMutation.isPending ? "Creating..." : "Create Household"}
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </div>
  );
}

server/migrations/create_order_id_counte.content:
import { db } from '../db.js';
import { sql } from 'drizzle-orm';

/**
 * Creates the order_id_counter sequence for generating unique order IDs
 * This sequence is used by the orderIdGenerator utility to create IDs in format: {counter}-{year}
 */
async function createOrderIdCounterSequence() {
  try {
    console.log('📊 Creating order_id_counter sequence...');

    // Create the sequence if it doesn't exist
    await db.execute(sql`
      CREATE SEQUENCE IF NOT EXISTS order_id_counter START WITH 1 INCREMENT BY 1;
    `);

    console.log('✅ order_id_counter sequence created successfully!');

    // Verify the sequence exists
    const result = await db.execute(sql`
      SELECT sequencename 
      FROM pg_sequences 
      WHERE sequencename = 'order_id_counter';
    `);

    if (result.rows.length > 0) {
      console.log('✅ Sequence verified:', result.rows[0]);
    } else {
      throw new Error('Sequence creation verification failed');
    }

  } catch (error: any) {
    console.error('❌ Migration failed:', error.message);
    throw error;
  }
}

// Run if executed directly
if (import.meta.url === `file://${process.argv[1]}`) {
  createOrderIdCounterSequence()
    .then(() => {
      console.log('✅ Migration completed successfully!');
      process.exit(0);
    })
    .catch((error) => {
      console.error('❌ Migration failed:', error);
      process.exit(1);
    });
}

export { createOrderIdCounterSequence };

server/src/routes/contact.ts.content:
import { Router } from 'express';
import { sendEmail } from '../../lib/email.js';
import rateLimit from 'express-rate-limit';

const router = Router();

const FROM_EMAIL = process.env.FROM_EMAIL || 'noreply@upkeepqr.com';
const ADMIN_EMAIL = process.env.ADMIN_EMAIL || 'support@upkeepqr.com';

// Rate limiting for contact form to prevent spam
const contactLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 requests per window
  message: {
    error: 'Too many contact submissions. Please try again in 15 minutes.'
  },
  standardHeaders: true,
  legacyHeaders: false,
});

/**
 * POST /api/contact
 * Handle contact form submissions
 * 
 * Request Body:
 * {
 *   name: string (required)
 *   email: string (required)
 *   phone?: string (optional)
 *   subject: string (required)
 *   message: string (required)
 * }
 * 
 * Response:
 * Success: { success: true, message: string }
 * Error: { error: string }
 */
router.post('/contact', contactLimiter, async (req, res) => {
  try {
    const { name, email, phone, subject, message } = req.body;

    // Validation
    if (!name || !email || !subject || !message) {
      return res.status(400).json({ 
        error: 'Name, email, subject, and message are required' 
      });
    }

    // Email validation (basic)
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(email)) {
      return res.status(400).json({ 
        error: 'Invalid email address' 
      });
    }

    // Send email to admin
    const emailSent = await sendEmail({
      to: ADMIN_EMAIL,
      from: FROM_EMAIL,
      subject: `Contact Form: ${subject}`,
      text: `
Contact Form Submission

Name: ${name}
Email: ${email}
Phone: ${phone || 'Not provided'}
Subject: ${subject}

Message:
${message}
      `,
      html: `
        <div style="font-family: Arial, sans-serif; max-width: 600px; margin: 0 auto;">
          <h2 style="color: #333;">New Contact Form Submission</h2>
          <div style="background: #f5f5f5; padding: 20px; border-radius: 5px; margin: 20px 0;">
            <p><strong>Name:</strong> ${name}</p>
            <p><strong>Email:</strong> <a href="mailto:${email}">${email}</a></p>
            <p><strong>Phone:</strong> ${phone || 'Not provided'}</p>
            <p><strong>Subject:</strong> ${subject}</p>
          </div>
          <div style="margin-top: 20px;">
            <h3 style="color: #333;">Message:</h3>
            <p style="white-space: pre-wrap; background: #ffffff; padding: 15px; border-left: 4px solid #A6E22E; border-radius: 4px;">${message}</p>
          </div>
          <hr style="margin: 30px 0; border: none; border-top: 1px solid #ddd;">
          <p style="font-size: 12px; color: #666;">
            Submitted at: ${new Date().toLocaleString()}<br>
            Reply to: <a href="mailto:${email}">${email}</a>
          </p>
        </div>
      `
    });

    if (!emailSent) {
      console.error('❌ Failed to send contact form email');
      return res.status(500).json({ 
        error: 'Failed to send message. Please try again or email us directly at support@upkeepqr.com' 
      });
    }

    // Log successful submission (for monitoring)
    console.log(`✅ Contact form submitted by ${name} (${email})`);

    // Success response
    res.json({ 
      success: true, 
      message: 'Thank you for contacting us! We will respond within 24 hours.' 
    });

  } catch (error) {
    // Log error for debugging
    console.error('❌ Contact form error:', error);

    // Return user-friendly error
    res.status(500).json({ 
      error: 'Failed to send message. Please try again or email us directly at support@upkeepqr.com' 
    });
  }
});

export default router;

